interface FollowRepository : JpaRepository<FollowEntity, String>, FollowQueryRepository {
    // 단건 조회 (팔로우 여부 확인)
    fun findByFollowerIdAndFollowingIdAndStatus(
        followerId: String,
        followingId: String,
        status: Int,
    ): FollowEntity?

    // 팔로우 수 카운트 (캐시 miss 시 fallback용)
