```

### 파일 5: `app/src/main/kotlin/com/maum/backend/service/follow/FollowService.kt`

```kotlin
// FollowService.kt - AFTER (Redis 캐시 + 최적화 쿼리 적용)
@Service
class FollowService(
    private val followRepository: FollowRepository,
    private val redisTemplate: RedisTemplate<String, Any>,
) {
    companion object {
        // TTL 전략: 팔로우 목록은 자주 변하지 않으므로 5분 캐시
        private const val FOLLOWING_LIST_TTL_SECONDS = 300L
        private const val FOLLOW_COUNT_TTL_SECONDS = 600L
        private const val FOLLOWING_LIST_KEY_PREFIX = "follow:following:"
        private const val FOLLOWER_LIST_KEY_PREFIX = "follow:follower:"
        private const val FOLLOWING_COUNT_KEY_PREFIX = "follow:count:following:"
        private const val FOLLOWER_COUNT_KEY_PREFIX = "follow:count:follower:"
    }

    // 최적화 7: Redis 캐시 + 단일 쿼리로 팔로잉 목록 조회
    // Before: SQL 101번, 캐시 없음 → After: 캐시 hit 시 SQL 0번, miss 시 SQL 1번
    fun getFollowingList(userId: String, pageable: Pageable): List<FollowUserProjection> {
        val cacheKey = "$FOLLOWING_LIST_KEY_PREFIX$userId:${pageable.pageNumber}"

        // 캐시 조회
        @Suppress("UNCHECKED_CAST")
        val cached = redisTemplate.opsForValue().get(cacheKey) as? List<FollowUserProjection>
        if (cached != null) return cached

        // 캐시 miss: DB 조회 (fetch join 1회)
        val result = followRepository.findFollowingList(userId, pageable)

        // 캐시 저장
        redisTemplate.opsForValue().set(cacheKey, result, FOLLOWING_LIST_TTL_SECONDS, TimeUnit.SECONDS)
        return result
    }

    fun getFollowerList(userId: String, pageable: Pageable): List<FollowUserProjection> {
        val cacheKey = "$FOLLOWER_LIST_KEY_PREFIX$userId:${pageable.pageNumber}"

        @Suppress("UNCHECKED_CAST")
        val cached = redisTemplate.opsForValue().get(cacheKey) as? List<FollowUserProjection>
        if (cached != null) return cached

        val result = followRepository.findFollowerList(userId, pageable)
        redisTemplate.opsForValue().set(cacheKey, result, FOLLOWING_LIST_TTL_SECONDS, TimeUnit.SECONDS)
        return result
    }

    // 최적화 8: 팔로우/언팔로우 시 캐시 무효화
    @Transactional
    fun follow(followerId: String, followingId: String) {
        val existing = followRepository.findByFollowerIdAndFollowingIdAndStatus(
            followerId, followingId, 0  // 비활성 상태 확인
        )
        if (existing != null) {
            // 재팔로우: status 업데이트
            // existing.activate() 형태로 처리
        } else {
            followRepository.save(
                FollowEntity(followerId = followerId, followingId = followingId)
            )
        }
        // 캐시 무효화: 팔로워/팔로잉 목록 및 카운트 모두 삭제
        invalidateFollowCache(followerId, followingId)
    }

    @Transactional
    fun unfollow(followerId: String, followingId: String) {
        val follow = followRepository.findByFollowerIdAndFollowingIdAndStatus(followerId, followingId, 1)
            ?: return
        // soft delete: status = 0
        // follow.deactivate() 형태로 처리
        invalidateFollowCache(followerId, followingId)
    }

    // 캐시 무효화: 팔로우 관계 변경 시 관련 키 전체 삭제
    private fun invalidateFollowCache(followerId: String, followingId: String) {
        val keys = redisTemplate.keys("$FOLLOWING_LIST_KEY_PREFIX$followerId:*") +
                redisTemplate.keys("$FOLLOWER_LIST_KEY_PREFIX$followingId:*") +
                setOf(
                    "$FOLLOWING_COUNT_KEY_PREFIX$followerId",
                    "$FOLLOWER_COUNT_KEY_PREFIX$followingId",
                )
        if (keys.isNotEmpty()) redisTemplate.delete(keys)
    }

    fun getFollowCounts(userId: String): FollowCountDto {
        val followingCountKey = "$FOLLOWING_COUNT_KEY_PREFIX$userId"
        val followerCountKey = "$FOLLOWER_COUNT_KEY_PREFIX$userId"

        val followingCount = redisTemplate.opsForValue().get(followingCountKey) as? Long
            ?: followRepository.countFollowing(userId).also {
                redisTemplate.opsForValue().set(followingCountKey, it, FOLLOW_COUNT_TTL_SECONDS, TimeUnit.SECONDS)
            }

        val followerCount = redisTemplate.opsForValue().get(followerCountKey) as? Long
            ?: followRepository.countFollower(userId).also {
                redisTemplate.opsForValue().set(followerCountKey, it, FOLLOW_COUNT_TTL_SECONDS, TimeUnit.SECONDS)
            }

        return FollowCountDto(followingCount = followingCount, followerCount = followerCount)
    }
}
```

